function solve(n: number): string {
    // Function to convert a number to a given base (hex or base36)
    function convertToBase(num: number, base: number): string {
        if (num === 0) return '0';
        let digits: string[] = [];
        while (num > 0) {
            let remainder = num % base;
            if (remainder < 10) {
                digits.push(remainder.toString());
            } else {
                digits.push(String.fromCharCode(65 + remainder - 10));
            }
            num = Math.floor(num / base);
        }
        return digits.reverse().join('');
    }

    // Calculate n squared and n cubed
    const n2 = n * n;
    const n3 = n * n * n;

    // Convert to hexadecimal and base36
    const hex = convertToBase(n2, 16);
    const base36 = convertToBase(n3, 36);

    // Concatenate and return
    return hex + base36;
}
